-- math: Ratios
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Ratios", "body": "A ratio compares two quantities. Worksheets use larger numbers as they go."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  There are 7 cats and 8 dogs. Write the ratio of cats to dogs (use a colon, like 3:4).\n\nThe answer is \"7:8\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  There are 2 red and 10 blue. Write the ratio of red to blue (use a colon, like 3:4).\n\nThe answer is \"2:10\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  There are 6 wins and 8 losses. Write the ratio of wins to losses (use a colon, like 3:4).\n\nThe answer is \"6:8\"."}, {"type": "worked_example", "title": "Worked example 4", "body": "Example 4.  There are 10 boys and 4 girls. Write the ratio of boys to girls (use a colon, like 3:4).\n\nThe answer is 10:4."}, {"type": "worked_example", "title": "Worked example 5", "body": "Example 5.  There are 11 wins and 17 losses. Write the ratio of wins to losses (use a colon, like 3:4).\n\nThe answer is 11:17."}, {"type": "worked_example", "title": "Worked example 6", "body": "Example 6.  There are 15 apples and 15 oranges. Write the ratio of apples to oranges (use a colon, like 3:4).\n\nThe answer is 15:15."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Ratios! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$math$tl$ and t.slug = $tl$ratios$tl$ and t.grade_level = 6);

-- math: Unit Rates
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Unit Rates", "body": "A unit rate tells how much of one quantity per one of another, like miles per hour."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  A car travels 24 miles in 3 hours at a steady speed. How many miles per hour is that?\n\nThe answer is \"8\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  A car travels 4 miles in 2 hours at a steady speed. How many miles per hour is that?\n\nThe answer is \"2\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  A car travels 27 miles in 3 hours at a steady speed. How many miles per hour is that?\n\nThe answer is \"9\"."}, {"type": "worked_example", "title": "Worked example 4", "body": "Example 4.  A car travels 76 miles in 4 hours at a steady speed. How many miles per hour is that?\n\nThe answer is 19."}, {"type": "worked_example", "title": "Worked example 5", "body": "Example 5.  A car travels 51 miles in 3 hours at a steady speed. How many miles per hour is that?\n\nThe answer is 17."}, {"type": "worked_example", "title": "Worked example 6", "body": "Example 6.  A car travels 48 miles in 4 hours at a steady speed. How many miles per hour is that?\n\nThe answer is 12."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Unit Rates! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$math$tl$ and t.slug = $tl$unit-rates$tl$ and t.grade_level = 6);

-- math: Percents
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Percents", "body": "A percent is a part out of 100. To find a percent of a number, multiply and divide by 100."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  What is 10% of 100?\n\nThe answer is \"10\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  What is 25% of 300?\n\nThe answer is \"75\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  What is 10% of 300?\n\nThe answer is \"30\"."}, {"type": "worked_example", "title": "Worked example 4", "body": "Example 4.  What is 50% of 600?\n\nThe answer is 300."}, {"type": "worked_example", "title": "Worked example 5", "body": "Example 5.  What is 75% of 200?\n\nThe answer is 150."}, {"type": "worked_example", "title": "Worked example 6", "body": "Example 6.  What is 20% of 400?\n\nThe answer is 80."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Percents! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$math$tl$ and t.slug = $tl$percent$tl$ and t.grade_level = 6);

-- math: Dividing Fractions
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Dividing Fractions", "body": "To divide by a fraction, multiply by its reciprocal (flip the second fraction)."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  2/3 / 1/3 = ?  (divide the fractions)\n\nThe answer is \"2\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  1/4 / 2/3 = ?  (divide the fractions)\n\nThe answer is \"3/8\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  1/3 / 1/3 = ?  (divide the fractions)\n\nThe answer is \"1\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "2/4 / 1/2 = ?  (divide the fractions)", "choices": [{"id": "a", "label": "1/4"}, {"id": "b", "label": "2"}, {"id": "c", "label": "4/5"}, {"id": "d", "label": "1"}], "answer": "d", "explanation": "Yes! The answer is \"1\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "1/2 / 1/2 = ?  (divide the fractions)", "choices": [{"id": "a", "label": "2/3"}, {"id": "b", "label": "1"}, {"id": "c", "label": "3/3"}, {"id": "d", "label": "1/4"}], "answer": "b", "explanation": "Yes! The answer is \"1\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "1/3 / 1/5 = ?  (divide the fractions)", "choices": [{"id": "a", "label": "5/3"}, {"id": "b", "label": "1/15"}, {"id": "c", "label": "6/4"}, {"id": "d", "label": "5/4"}], "answer": "a", "explanation": "Yes! The answer is \"5/3\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Dividing Fractions! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$math$tl$ and t.slug = $tl$divide-fractions$tl$ and t.grade_level = 6);

-- math: Decimal Operations
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Decimal Operations", "body": "Add, subtract, and multiply decimals carefully, keeping track of the decimal point."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  0.7 + 0.9 = ?\n\nThe answer is \"1.6\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  3.4 + 0.5 = ?\n\nThe answer is \"3.9\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  2 - 0.4 = ?\n\nThe answer is \"1.6\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "1.4 - 0.9 = ?", "choices": [{"id": "a", "label": "0.5"}, {"id": "b", "label": "5"}, {"id": "c", "label": "0.4"}, {"id": "d", "label": "0.6"}], "answer": "a", "explanation": "Yes! The answer is \"0.5\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "0.5 - 0.2 = ?", "choices": [{"id": "a", "label": "0.5"}, {"id": "b", "label": "0.3"}, {"id": "c", "label": "0.4"}, {"id": "d", "label": "0.2"}], "answer": "b", "explanation": "Yes! The answer is \"0.3\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "3.4 + 0.7 = ?", "choices": [{"id": "a", "label": "4"}, {"id": "b", "label": "4.2"}, {"id": "c", "label": "4.1"}, {"id": "d", "label": "41"}], "answer": "c", "explanation": "Yes! The answer is \"4.1\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Decimal Operations! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
