-- math: GCF & LCM
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: GCF & LCM", "body": "The GCF is the biggest factor two numbers share; the LCM is the smallest multiple they share."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  What is the LCM (least common multiple) of 4 and 5?\n\nThe answer is \"20\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  What is the LCM (least common multiple) of 10 and 11?\n\nThe answer is \"110\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  What is the LCM (least common multiple) of 2 and 6?\n\nThe answer is \"6\"."}, {"type": "worked_example", "title": "Worked example 4", "body": "Example 4.  What is the GCF (greatest common factor) of 9 and 16?\n\nThe answer is 1."}, {"type": "worked_example", "title": "Worked example 5", "body": "Example 5.  What is the GCF (greatest common factor) of 10 and 20?\n\nThe answer is 10."}, {"type": "worked_example", "title": "Worked example 6", "body": "Example 6.  What is the LCM (least common multiple) of 4 and 13?\n\nThe answer is 52."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about GCF & LCM! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$math$tl$ and t.slug = $tl$gcf-lcm$tl$ and t.grade_level = 6);

-- math: Integers & Absolute Value
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Integers & Absolute Value", "body": "Integers include negative numbers; absolute value is a number's distance from zero."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  What is the absolute value |-2| ?\n\nThe answer is \"2\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  What is the absolute value |-8| ?\n\nThe answer is \"8\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  What is the absolute value |-9| ?\n\nThe answer is \"9\"."}, {"type": "worked_example", "title": "Worked example 4", "body": "Example 4.  What is the absolute value |-5| ?\n\nThe answer is 5."}, {"type": "worked_example", "title": "Worked example 5", "body": "Example 5.  What is the absolute value |-14| ?\n\nThe answer is 14."}, {"type": "worked_example", "title": "Worked example 6", "body": "Example 6.  What is 18 - 17 - 17 ?\n\nThe answer is -16."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Integers & Absolute Value! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
