-- math: Exponents
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Exponents", "body": "An exponent tells how many times to multiply a base by itself, like 2^3 = 8."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  What is 6^2 (that is 6 to the power 2)?\n\nThe answer is \"36\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  What is 7^2 (that is 7 to the power 2)?\n\nThe answer is \"49\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  What is 5^2 (that is 5 to the power 2)?\n\nThe answer is \"25\"."}, {"type": "worked_example", "title": "Worked example 4", "body": "Example 4.  What is 12^2 (that is 12 to the power 2)?\n\nThe answer is 144."}, {"type": "worked_example", "title": "Worked example 5", "body": "Example 5.  What is 9^2 (that is 9 to the power 2)?\n\nThe answer is 81."}, {"type": "worked_example", "title": "Worked example 6", "body": "Example 6.  What is 11^2 (that is 11 to the power 2)?\n\nThe answer is 121."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Exponents! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
