  where s.slug = $tl$math$tl$ and t.slug = $tl$exponents$tl$ and t.grade_level = 6);

-- math: Evaluating Expressions
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Evaluating Expressions", "body": "Substitute the given value for the variable, then follow the order of operations."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Evaluate 4x + 7 when x = 7.\n\nThe answer is \"35\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Evaluate 4x + 7 when x = 5.\n\nThe answer is \"27\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Evaluate 5x + 3 when x = 9.\n\nThe answer is \"48\"."}, {"type": "worked_example", "title": "Worked example 4", "body": "Example 4.  Evaluate 4x - 9 when x = 10.\n\nThe answer is 31."}, {"type": "worked_example", "title": "Worked example 5", "body": "Example 5.  Evaluate 7x - 3 when x = 10.\n\nThe answer is 67."}, {"type": "worked_example", "title": "Worked example 6", "body": "Example 6.  Evaluate 6x - 5 when x = 4.\n\nThe answer is 19."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Evaluating Expressions! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
