update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: One-Step Equations", "body": "Use the inverse operation to get the variable by itself and solve."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Solve for x:  x + 4 = 17\n\nThe answer is \"13\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Solve for x:  x + 12 = 17\n\nThe answer is \"5\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Solve for x:  x + 7 = 17\n\nThe answer is \"10\"."}, {"type": "worked_example", "title": "Worked example 4", "body": "Example 4.  Solve for x:  x - 5 = 12\n\nThe answer is 17."}, {"type": "worked_example", "title": "Worked example 5", "body": "Example 5.  Solve for x:  x - 14 = -11\n\nThe answer is 3."}, {"type": "worked_example", "title": "Worked example 6", "body": "Example 6.  Solve for x:  x - 18 = 0\n\nThe answer is 18."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about One-Step Equations! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
