  where s.slug = $tl$math$tl$ and t.slug = $tl$one-step-equations$tl$ and t.grade_level = 6);

-- science: Cells
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Cells", "body": "Cells are the basic building blocks of all living things; some have specialized parts."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  The basic building block of all living things is the:\n\nThe answer is \"cell\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Living things made of many cells are called:\n\nThe answer is \"multicellular\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  A living thing made of only one cell is:\n\nThe answer is \"unicellular\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "The part of the cell that controls its activities is the:", "choices": [{"id": "a", "label": "nucleus"}, {"id": "b", "label": "cell wall"}, {"id": "c", "label": "vacuole"}, {"id": "d", "label": "ribosome"}], "answer": "a", "explanation": "Yes! The answer is \"nucleus\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Plant cells have a stiff outer layer that animal cells lack, the:", "choices": [{"id": "a", "label": "nucleus"}, {"id": "b", "label": "cytoplasm"}, {"id": "c", "label": "membrane"}, {"id": "d", "label": "cell wall"}], "answer": "d", "explanation": "Yes! The answer is \"cell wall\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "The thin layer that controls what enters and leaves a cell is the:", "choices": [{"id": "a", "label": "cell wall"}, {"id": "b", "label": "nucleus"}, {"id": "c", "label": "cell membrane"}, {"id": "d", "label": "vacuole"}], "answer": "c", "explanation": "Yes! The answer is \"cell membrane\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Cells! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$science$tl$ and t.slug = $tl$cells$tl$ and t.grade_level = 6);

-- science: Body Systems
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Body Systems", "body": "The body's organ systems work together to keep an organism alive and healthy."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  The system that pumps blood through the body is the:\n\nThe answer is \"circulatory system\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  The system that breaks down food into nutrients is the:\n\nThe answer is \"digestive system\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  The system that takes in oxygen and removes carbon dioxide is the:\n\nThe answer is \"respiratory system\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Bones that support and protect the body make up the:", "choices": [{"id": "a", "label": "muscular system"}, {"id": "b", "label": "skeletal system"}, {"id": "c", "label": "nervous system"}, {"id": "d", "label": "digestive system"}], "answer": "b", "explanation": "Yes! The answer is \"skeletal system\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Muscles that let the body move are part of the:", "choices": [{"id": "a", "label": "skeletal system"}, {"id": "b", "label": "muscular system"}, {"id": "c", "label": "nervous system"}, {"id": "d", "label": "circulatory system"}], "answer": "b", "explanation": "Yes! The answer is \"muscular system\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "The brain, spinal cord, and nerves form the:", "choices": [{"id": "a", "label": "circulatory system"}, {"id": "b", "label": "digestive system"}, {"id": "c", "label": "respiratory system"}, {"id": "d", "label": "nervous system"}], "answer": "d", "explanation": "Yes! The answer is \"nervous system\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Body Systems! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
