-- science: Ecosystems & Energy
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Ecosystems & Energy", "body": "Energy flows and matter cycles through producers, consumers, and decomposers."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Energy enters most ecosystems from the:\n\nThe answer is \"Sun\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Organisms that make their own food are:\n\nThe answer is \"producers\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Organisms that eat other organisms are:\n\nThe answer is \"consumers\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Organisms that break down dead matter are:", "choices": [{"id": "a", "label": "producers"}, {"id": "b", "label": "decomposers"}, {"id": "c", "label": "predators"}, {"id": "d", "label": "herbivores"}], "answer": "b", "explanation": "Yes! The answer is \"decomposers\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "In a food chain, arrows show the flow of:", "choices": [{"id": "a", "label": "energy"}, {"id": "b", "label": "water"}, {"id": "c", "label": "air"}, {"id": "d", "label": "money"}], "answer": "a", "explanation": "Yes! The answer is \"energy\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "At each step of a food chain, most energy is lost as:", "choices": [{"id": "a", "label": "matter"}, {"id": "b", "label": "light"}, {"id": "c", "label": "heat"}, {"id": "d", "label": "sound"}], "answer": "c", "explanation": "Yes! The answer is \"heat\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Ecosystems & Energy! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
