-- science: Weather & Climate
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Weather & Climate", "body": "Weather is short-term; climate is long-term. Both depend on the atmosphere and oceans."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Weather is the condition of the atmosphere:\n\nThe answer is \"over a short time\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Climate is the typical weather of a place:\n\nThe answer is \"over many years\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Most weather happens in the lowest layer of the atmosphere, the:\n\nThe answer is \"troposphere\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Warm air tends to:", "choices": [{"id": "a", "label": "rise"}, {"id": "b", "label": "sink"}, {"id": "c", "label": "stay still"}, {"id": "d", "label": "freeze"}], "answer": "a", "explanation": "Yes! The answer is \"rise\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "A large body of air with similar temperature and humidity is an:", "choices": [{"id": "a", "label": "ocean current"}, {"id": "b", "label": "mountain"}, {"id": "c", "label": "rock layer"}, {"id": "d", "label": "air mass"}], "answer": "d", "explanation": "Yes! The answer is \"air mass\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "The boundary where two air masses meet is a:", "choices": [{"id": "a", "label": "coast"}, {"id": "b", "label": "front"}, {"id": "c", "label": "fault"}, {"id": "d", "label": "crater"}], "answer": "b", "explanation": "Yes! The answer is \"front\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Weather & Climate! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$science$tl$ and t.slug = $tl$weather-and-climate$tl$ and t.grade_level = 6);

-- science: Plate Tectonics
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Plate Tectonics", "body": "Earth's plates move slowly, shaping continents and causing earthquakes and volcanoes."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Earth's outer shell is broken into large pieces called:\n\nThe answer is \"tectonic plates\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Tectonic plates float and move slowly on the:\n\nThe answer is \"mantle\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Where two plates pull apart, new crust can form. This is a:\n\nThe answer is \"divergent boundary\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Where two plates push together is a:", "choices": [{"id": "a", "label": "divergent boundary"}, {"id": "b", "label": "transform boundary"}, {"id": "c", "label": "valley"}, {"id": "d", "label": "convergent boundary"}], "answer": "d", "explanation": "Yes! The answer is \"convergent boundary\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Where two plates slide past each other is a:", "choices": [{"id": "a", "label": "divergent boundary"}, {"id": "b", "label": "transform boundary"}, {"id": "c", "label": "convergent boundary"}, {"id": "d", "label": "trench"}], "answer": "b", "explanation": "Yes! The answer is \"transform boundary\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Most earthquakes and volcanoes occur:", "choices": [{"id": "a", "label": "in the middle of plates only"}, {"id": "b", "label": "in the sky"}, {"id": "c", "label": "near plate boundaries"}, {"id": "d", "label": "underwater only"}], "answer": "c", "explanation": "Yes! The answer is \"near plate boundaries\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Plate Tectonics! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$science$tl$ and t.slug = $tl$plate-tectonics$tl$ and t.grade_level = 6);

-- science: The Rock Cycle
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: The Rock Cycle", "body": "Rocks change between igneous, sedimentary, and metamorphic forms over time."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Rock formed from cooled magma or lava is:\n\nThe answer is \"igneous rock\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Rock formed from compacted layers of sediment is:\n\nThe answer is \"sedimentary rock\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Rock changed by heat and pressure is:\n\nThe answer is \"metamorphic rock\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Fossils are most commonly found in which rock type?", "choices": [{"id": "a", "label": "igneous"}, {"id": "b", "label": "metamorphic"}, {"id": "c", "label": "sedimentary"}, {"id": "d", "label": "molten"}], "answer": "c", "explanation": "Yes! The answer is \"sedimentary\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "The breaking down of rock into smaller pieces is:", "choices": [{"id": "a", "label": "deposition"}, {"id": "b", "label": "melting"}, {"id": "c", "label": "cementing"}, {"id": "d", "label": "weathering"}], "answer": "d", "explanation": "Yes! The answer is \"weathering\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Wind and water moving sediment from place to place is:", "choices": [{"id": "a", "label": "weathering"}, {"id": "b", "label": "melting"}, {"id": "c", "label": "erosion"}, {"id": "d", "label": "cooling"}], "answer": "c", "explanation": "Yes! The answer is \"erosion\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about The Rock Cycle! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$science$tl$ and t.slug = $tl$rock-cycle$tl$ and t.grade_level = 6);

-- science: The Solar System
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: The Solar System", "body": "Gravity holds planets, moons, asteroids, and comets in orbit around the Sun."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  The Sun is at the center of our solar system and is a:\n\nThe answer is \"star\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  The planets move around the Sun in paths called:\n\nThe answer is \"orbits\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Which force keeps the planets in orbit around the Sun?\n\nThe answer is \"gravity\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "The four inner planets are small and made mostly of:", "choices": [{"id": "a", "label": "gas"}, {"id": "b", "label": "ice only"}, {"id": "c", "label": "light"}, {"id": "d", "label": "rock"}], "answer": "d", "explanation": "Yes! The answer is \"rock\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "The four outer planets are large and made mostly of:", "choices": [{"id": "a", "label": "rock"}, {"id": "b", "label": "metal only"}, {"id": "c", "label": "gas"}, {"id": "d", "label": "water"}], "answer": "c", "explanation": "Yes! The answer is \"gas\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Earth takes about one ____ to orbit the Sun.", "choices": [{"id": "a", "label": "day"}, {"id": "b", "label": "month"}, {"id": "c", "label": "hour"}, {"id": "d", "label": "year"}], "answer": "d", "explanation": "Yes! The answer is \"year\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about The Solar System! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
