  where s.slug = $tl$science$tl$ and t.slug = $tl$solar-system$tl$ and t.grade_level = 6);

-- science: Atoms & Matter
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Atoms & Matter", "body": "Matter is made of atoms; substances can be elements, compounds, or mixtures."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  The smallest unit of an element is an:\n\nThe answer is \"atom\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Two or more atoms joined together form a:\n\nThe answer is \"molecule\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  A substance made of only one kind of atom is an:\n\nThe answer is \"element\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Water (H2O) is made of hydrogen and oxygen, so it is a:", "choices": [{"id": "a", "label": "element"}, {"id": "b", "label": "mixture"}, {"id": "c", "label": "compound"}, {"id": "d", "label": "atom"}], "answer": "c", "explanation": "Yes! The answer is \"compound\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "In a solid, particles are packed closely and:", "choices": [{"id": "a", "label": "move freely and far apart"}, {"id": "b", "label": "vibrate in place"}, {"id": "c", "label": "disappear"}, {"id": "d", "label": "do not exist"}], "answer": "b", "explanation": "Yes! The answer is \"vibrate in place\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "In a gas, particles:", "choices": [{"id": "a", "label": "are locked in place"}, {"id": "b", "label": "are a liquid"}, {"id": "c", "label": "vanish"}, {"id": "d", "label": "move quickly and spread far apart"}], "answer": "d", "explanation": "Yes! The answer is \"move quickly and spread far apart\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Atoms & Matter! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$science$tl$ and t.slug = $tl$atoms-and-matter$tl$ and t.grade_level = 6);

-- science: Energy & Its Transfer
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Energy & Its Transfer", "body": "Energy can be stored or moving and is transferred by conduction, convection, and radiation."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Energy that an object has because it is moving is:\n\nThe answer is \"kinetic energy\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Stored energy due to position, like a raised ball, is:\n\nThe answer is \"potential energy\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Energy cannot be created or destroyed, only:\n\nThe answer is \"transferred or transformed\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Heat moving through a metal spoon in soup is:", "choices": [{"id": "a", "label": "convection"}, {"id": "b", "label": "radiation"}, {"id": "c", "label": "conduction"}, {"id": "d", "label": "reflection"}], "answer": "c", "explanation": "Yes! The answer is \"conduction\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Heat carried by moving liquids or gases is:", "choices": [{"id": "a", "label": "conduction"}, {"id": "b", "label": "convection"}, {"id": "c", "label": "radiation"}, {"id": "d", "label": "insulation"}], "answer": "b", "explanation": "Yes! The answer is \"convection\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Heat from the Sun reaching Earth through space is:", "choices": [{"id": "a", "label": "conduction"}, {"id": "b", "label": "convection"}, {"id": "c", "label": "radiation"}, {"id": "d", "label": "friction"}], "answer": "c", "explanation": "Yes! The answer is \"radiation\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Energy & Its Transfer! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$science$tl$ and t.slug = $tl$energy-transfer$tl$ and t.grade_level = 6);

-- science: Forces & Motion
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Forces & Motion", "body": "Forces change motion; balanced forces keep it steady while unbalanced forces change it."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  A push or a pull is a:\n\nThe answer is \"force\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  The tendency of an object to resist changes in motion is:\n\nThe answer is \"inertia\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  An object at rest stays at rest unless acted on by an:\n\nThe answer is \"unbalanced force\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Forces that are equal and opposite are:", "choices": [{"id": "a", "label": "unbalanced"}, {"id": "b", "label": "balanced"}, {"id": "c", "label": "negative"}, {"id": "d", "label": "invisible"}], "answer": "b", "explanation": "Yes! The answer is \"balanced\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Unbalanced forces cause an object's motion to:", "choices": [{"id": "a", "label": "stay exactly the same"}, {"id": "b", "label": "disappear"}, {"id": "c", "label": "change"}, {"id": "d", "label": "reverse time"}], "answer": "c", "explanation": "Yes! The answer is \"change\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "The force that opposes motion between surfaces is:", "choices": [{"id": "a", "label": "gravity"}, {"id": "b", "label": "magnetism"}, {"id": "c", "label": "inertia"}, {"id": "d", "label": "friction"}], "answer": "d", "explanation": "Yes! The answer is \"friction\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Forces & Motion! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$science$tl$ and t.slug = $tl$forces-and-motion$tl$ and t.grade_level = 6);

-- reading: Central Idea
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Central Idea", "body": "The central idea is a text's most important overall point, developed by details."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  The central idea of a text is its:\n\nThe answer is \"most important overall point\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Supporting details in a text serve to:\n\nThe answer is \"develop the central idea\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Read: \"Bees pollinate crops, support ecosystems, and produce honey, making them vital.\" The central idea is that bees are:\n\nThe answer is \"important to humans and nature\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "To find the central idea, you should consider the text as a:", "choices": [{"id": "a", "label": "single word"}, {"id": "b", "label": "whole"}, {"id": "c", "label": "title only"}, {"id": "d", "label": "page number"}], "answer": "b", "explanation": "Yes! The answer is \"whole\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "A central idea is usually:", "choices": [{"id": "a", "label": "supported by several details"}, {"id": "b", "label": "stated as a question"}, {"id": "c", "label": "a random fact"}, {"id": "d", "label": "the shortest sentence"}], "answer": "a", "explanation": "Yes! The answer is \"supported by several details\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"Despite setbacks, the team kept testing until their rover finally worked.\" The central idea is about:", "choices": [{"id": "a", "label": "building cars"}, {"id": "b", "label": "spending money"}, {"id": "c", "label": "the color of the rover"}, {"id": "d", "label": "persistence leading to success"}], "answer": "d", "explanation": "Yes! The answer is \"persistence leading to success\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Central Idea! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$reading$tl$ and t.slug = $tl$central-idea$tl$ and t.grade_level = 6);

-- reading: Theme
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Theme", "body": "A theme is a story's underlying message about life, shown through the characters."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  A theme is a story's:\n\nThe answer is \"underlying message about life\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Theme differs from topic because theme is a:\n\nThe answer is \"complete idea or lesson\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Read: \"Though small and doubted, the girl's idea saved the village.\" A theme is:\n\nThe answer is \"everyone's contribution matters\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Authors usually reveal theme through:", "choices": [{"id": "a", "label": "the title page only"}, {"id": "b", "label": "characters' actions and changes"}, {"id": "c", "label": "the font"}, {"id": "d", "label": "the price"}], "answer": "b", "explanation": "Yes! The answer is \"characters' actions and changes\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "A story where greed leads to ruin develops a theme about the:", "choices": [{"id": "a", "label": "joy of greed"}, {"id": "b", "label": "size of houses"}, {"id": "c", "label": "dangers of greed"}, {"id": "d", "label": "weather"}], "answer": "c", "explanation": "Yes! The answer is \"dangers of greed\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Two very different stories can share a theme such as:", "choices": [{"id": "a", "label": "the same exact plot"}, {"id": "b", "label": "the same author"}, {"id": "c", "label": "courage in the face of fear"}, {"id": "d", "label": "the same length"}], "answer": "c", "explanation": "Yes! The answer is \"courage in the face of fear\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Theme! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$reading$tl$ and t.slug = $tl$theme$tl$ and t.grade_level = 6);

-- reading: Objective Summary
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Objective Summary", "body": "An objective summary briefly restates the central idea and key details without opinion."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  An objective summary should:\n\nThe answer is \"stay neutral and factual\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  A good summary is ____ than the original.\n\nThe answer is \"shorter\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  A summary should capture the central idea and the:\n\nThe answer is \"most important details\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "When summarizing, restate ideas in your:", "choices": [{"id": "a", "label": "the author's exact words"}, {"id": "b", "label": "own words"}, {"id": "c", "label": "a code"}, {"id": "d", "label": "emojis only"}], "answer": "b", "explanation": "Yes! The answer is \"own words\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Which should be LEFT OUT of an objective summary?", "choices": [{"id": "a", "label": "your personal feelings"}, {"id": "b", "label": "the main idea"}, {"id": "c", "label": "key supporting points"}, {"id": "d", "label": "the topic"}], "answer": "a", "explanation": "Yes! The answer is \"your personal feelings\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Events in a narrative summary should appear in:", "choices": [{"id": "a", "label": "random order"}, {"id": "b", "label": "reverse only"}, {"id": "c", "label": "logical order"}, {"id": "d", "label": "no order"}], "answer": "c", "explanation": "Yes! The answer is \"logical order\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Objective Summary! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$reading$tl$ and t.slug = $tl$summarizing$tl$ and t.grade_level = 6);

-- reading: Citing Text Evidence
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Citing Text Evidence", "body": "Support your ideas and inferences with specific evidence taken from the text."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Text evidence is information you take ____ from the text to support an answer.\n\nThe answer is \"directly\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  To support a claim about a text, you should cite:\n\nThe answer is \"specific details or quotes\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  An inference must be supported by:\n\nThe answer is \"evidence in the text\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "'The text states...' is a phrase used to:", "choices": [{"id": "a", "label": "introduce evidence"}, {"id": "b", "label": "end an essay"}, {"id": "c", "label": "change topics"}, {"id": "d", "label": "give an opinion"}], "answer": "a", "explanation": "Yes! The answer is \"introduce evidence\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Strong evidence is:", "choices": [{"id": "a", "label": "relevant and from the text"}, {"id": "b", "label": "off-topic"}, {"id": "c", "label": "made up"}, {"id": "d", "label": "about the author's age"}], "answer": "a", "explanation": "Yes! The answer is \"relevant and from the text\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "When asked 'how do you know?', a good reader:", "choices": [{"id": "a", "label": "guesses"}, {"id": "b", "label": "ignores the text"}, {"id": "c", "label": "talks about lunch"}, {"id": "d", "label": "points to text evidence"}], "answer": "d", "explanation": "Yes! The answer is \"points to text evidence\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Citing Text Evidence! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$reading$tl$ and t.slug = $tl$citing-evidence$tl$ and t.grade_level = 6);

