update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Author's Purpose & View", "body": "Authors write to inform, persuade, or entertain, often revealing a point of view."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  An author's purpose for writing might be to inform, entertain, or:\n\nThe answer is \"persuade\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  An author's point of view is their:\n\nThe answer is \"attitude or stance on a topic\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  A text that argues you should recycle is mainly meant to:\n\nThe answer is \"persuade\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Word choices that show strong feelings can reveal the author's:", "choices": [{"id": "a", "label": "page number"}, {"id": "b", "label": "font"}, {"id": "c", "label": "price"}, {"id": "d", "label": "point of view / bias"}], "answer": "d", "explanation": "Yes! The answer is \"point of view / bias\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "An encyclopedia entry's purpose is usually to:", "choices": [{"id": "a", "label": "persuade"}, {"id": "b", "label": "entertain"}, {"id": "c", "label": "inform"}, {"id": "d", "label": "sell"}], "answer": "c", "explanation": "Yes! The answer is \"inform\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "To find an author's purpose, ask:", "choices": [{"id": "a", "label": "how long is it?"}, {"id": "b", "label": "who printed it?"}, {"id": "c", "label": "what is the cover?"}, {"id": "d", "label": "why did they write this?"}], "answer": "d", "explanation": "Yes! The answer is \"why did they write this?\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Author's Purpose & View! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
