-- reading: Word Meaning
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Word Meaning", "body": "Use context clues, prefixes, suffixes, and roots to determine word meanings."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Read: \"The benevolent leader gave generously to the poor.\" \"Benevolent\" means:\n\nThe answer is \"kind / generous\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Read: \"His incessant talking never stopped all day.\" \"Incessant\" means:\n\nThe answer is \"constant / nonstop\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Read: \"The drought made the once-fertile land barren.\" \"Barren\" means:\n\nThe answer is \"empty / unable to grow life\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "The prefix 'un-' in 'unhappy' means:", "choices": [{"id": "a", "label": "not"}, {"id": "b", "label": "very"}, {"id": "c", "label": "again"}, {"id": "d", "label": "before"}], "answer": "a", "explanation": "Yes! The answer is \"not\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "The root 'aqua' in 'aquarium' relates to:", "choices": [{"id": "a", "label": "fire"}, {"id": "b", "label": "air"}, {"id": "c", "label": "water"}, {"id": "d", "label": "earth"}], "answer": "c", "explanation": "Yes! The answer is \"water\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"She was reluctant and hesitated to agree.\" \"Reluctant\" means:", "choices": [{"id": "a", "label": "eager"}, {"id": "b", "label": "angry"}, {"id": "c", "label": "unwilling"}, {"id": "d", "label": "tired"}], "answer": "c", "explanation": "Yes! The answer is \"unwilling\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Word Meaning! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
