update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Figurative Language", "body": "Similes, metaphors, personification, idioms, and hyperbole add meaning and imagery."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  \"The world is a stage\" is a:\n\nThe answer is \"metaphor\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  \"As brave as a lion\" is a:\n\nThe answer is \"simile\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Giving human traits to nonhuman things is:\n\nThe answer is \"personification\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "\"I have a ton of homework\" is an exaggeration called:", "choices": [{"id": "a", "label": "simile"}, {"id": "b", "label": "metaphor"}, {"id": "c", "label": "hyperbole"}, {"id": "d", "label": "idiom"}], "answer": "c", "explanation": "Yes! The answer is \"hyperbole\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "An expression like 'spill the beans' whose meaning isn't literal is an:", "choices": [{"id": "a", "label": "idiom"}, {"id": "b", "label": "simile"}, {"id": "c", "label": "metaphor"}, {"id": "d", "label": "onomatopoeia"}], "answer": "a", "explanation": "Yes! The answer is \"idiom\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Words like 'crash' and 'hiss' that imitate sounds are:", "choices": [{"id": "a", "label": "similes"}, {"id": "b", "label": "onomatopoeia"}, {"id": "c", "label": "metaphors"}, {"id": "d", "label": "idioms"}], "answer": "b", "explanation": "Yes! The answer is \"onomatopoeia\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Figurative Language! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
